import { useState, useRef, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { generateTartan, DEFAULT_CONSTRAINTS, CONSTRAINT_PRESETS } from '../core/generator';
import { parseThreadcount, toThreadcountString, generateSignatures } from '../core/sett';
import { renderTartanToCanvas } from '../utils/renderTartan';
import type { GeneratorResult, GeneratorConstraints, WeaveType } from '../core/types';
import WeaveSelector from '../components/WeaveSelector';

// ---------------------------------------------------------------------------
// History item thumbnail
// ---------------------------------------------------------------------------

function HistoryThumb({
  result,
  isActive,
  onClick,
}: {
  result: GeneratorResult;
  isActive: boolean;
  onClick: () => void;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [rendered, setRendered] = useState(false);
  const tc = toThreadcountString(result.sett);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, tc, 120);
      setRendered(true);
    }
  }, [tc]);

  return (
    <button
      onClick={onClick}
      className={`flex-shrink-0 rounded-lg overflow-hidden border-2 transition-all duration-200
                  w-16 h-16 sm:w-20 sm:h-20
                  ${isActive
                    ? 'border-[var(--accent)] shadow-sm'
                    : 'border-[var(--border)] hover:border-[var(--border-hover)]'}`}
    >
      {!rendered && <div className="w-full h-full animate-shimmer" />}
      <canvas
        ref={canvasRef}
        className={`w-full h-full ${rendered ? '' : 'opacity-0 absolute'}`}
        style={{ imageRendering: 'pixelated' }}
      />
    </button>
  );
}

// ---------------------------------------------------------------------------
// Main canvas for current result
// ---------------------------------------------------------------------------

function MainPreview({ threadcount, weave }: { threadcount: string; weave: WeaveType }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (canvasRef.current) {
      renderTartanToCanvas(canvasRef.current, threadcount, 600, weave);
    }
  }, [threadcount, weave]);

  return (
    <div className="rounded-xl overflow-hidden border border-[var(--border)] bg-[var(--bg-card)] shadow-sm">
      <canvas
        ref={canvasRef}
        className="w-full aspect-square"
        style={{ imageRendering: 'pixelated' }}
      />
    </div>
  );
}

// ---------------------------------------------------------------------------
// Generate page
// ---------------------------------------------------------------------------

export default function GeneratePage() {
  const [searchParams] = useSearchParams();
  const [history, setHistory] = useState<GeneratorResult[]>([]);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [weave, setWeave] = useState<WeaveType>('twill-2-2');
  const [showConstraints, setShowConstraints] = useState(false);
  const [preset, setPreset] = useState<string>('classic');
  const [constraints, setConstraints] = useState<GeneratorConstraints>({
    ...DEFAULT_CONSTRAINTS,
    ...CONSTRAINT_PRESETS['classic'],
  });

  // Check for passed-in threadcount from breed panel
  const passedTc = searchParams.get('tc');
  const passedName = searchParams.get('name');

  // Initialize with passed threadcount if present
  useEffect(() => {
    if (passedTc && history.length === 0) {
      try {
        const sett = parseThreadcount(passedTc);
        const signature = generateSignatures(sett);
        const fakeResult: GeneratorResult = {
          sett,
          seed: 0,
          constraints,
          signature,
        };
        setHistory([fakeResult]);
        setActiveIndex(0);
      } catch {
        // If passed TC is invalid, just ignore
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const activeResult = activeIndex >= 0 ? history[activeIndex] : null;
  const activeThreadcount = activeResult ? toThreadcountString(activeResult.sett) : '';

  const generate = useCallback(() => {
    const result = generateTartan(constraints);
    setHistory((prev) => [result, ...prev]);
    setActiveIndex(0);
  }, [constraints]);

  const handlePresetChange = useCallback((newPreset: string) => {
    setPreset(newPreset);
    if (CONSTRAINT_PRESETS[newPreset]) {
      setConstraints({ ...DEFAULT_CONSTRAINTS, ...CONSTRAINT_PRESETS[newPreset] });
    }
  }, []);

  const handleRangeChange = useCallback((
    key: 'colorCount' | 'stripeCount' | 'threadCount' | 'totalThreads',
    bound: 'min' | 'max',
    value: number
  ) => {
    setConstraints((prev) => ({
      ...prev,
      [key]: {
        ...prev[key],
        [bound]: value,
      },
    }));
    setPreset('custom');
  }, []);

  return (
    <div className="min-h-screen">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 py-6 sm:py-10 space-y-8">

        {/* Header */}
        <div>
          <h1 className="text-2xl sm:text-3xl font-serif font-normal text-[var(--text)]">
            {passedName || 'Generate'}
          </h1>
          <p className="text-sm text-[var(--text-secondary)] mt-1">
            Create random tartans with configurable constraints
          </p>
        </div>

        {/* Generate button */}
        <div className="flex items-center gap-4">
          <button
            onClick={generate}
            className="px-8 py-3 rounded-lg text-sm font-medium
                       bg-[var(--accent)] text-white
                       hover:opacity-90 transition-all duration-200
                       active:scale-[0.98]"
          >
            Generate Tartan
          </button>

          <button
            onClick={() => setShowConstraints(!showConstraints)}
            className="text-sm text-[var(--text-secondary)] hover:text-[var(--text)] transition-colors"
          >
            {showConstraints ? 'Hide constraints' : 'Show constraints'}
          </button>
        </div>

        {/* Constraints panel */}
        {showConstraints && (
          <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-xl p-5 space-y-5 animate-fadeIn">
            {/* Presets */}
            <div>
              <label className="text-xs font-mono uppercase tracking-widest text-[var(--text-tertiary)] block mb-2">
                Preset
              </label>
              <div className="flex gap-2 flex-wrap">
                {['simple', 'classic', 'complex', 'minimal', 'hunting', 'dress'].map((p) => (
                  <button
                    key={p}
                    onClick={() => handlePresetChange(p)}
                    className={`pill text-xs capitalize
                      ${preset === p ? 'pill-active' : 'pill-inactive'}`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>

            {/* Range controls */}
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <RangeControl
                label="Colors"
                min={constraints.colorCount.min}
                max={constraints.colorCount.max}
                absMin={2}
                absMax={8}
                onMinChange={(v) => handleRangeChange('colorCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('colorCount', 'max', v)}
              />
              <RangeControl
                label="Stripes"
                min={constraints.stripeCount.min}
                max={constraints.stripeCount.max}
                absMin={2}
                absMax={16}
                onMinChange={(v) => handleRangeChange('stripeCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('stripeCount', 'max', v)}
              />
              <RangeControl
                label="Threads per stripe"
                min={constraints.threadCount.min}
                max={constraints.threadCount.max}
                absMin={2}
                absMax={64}
                onMinChange={(v) => handleRangeChange('threadCount', 'min', v)}
                onMaxChange={(v) => handleRangeChange('threadCount', 'max', v)}
              />
              <RangeControl
                label="Total threads"
                min={constraints.totalThreads.min}
                max={constraints.totalThreads.max}
                absMin={20}
                absMax={400}
                onMinChange={(v) => handleRangeChange('totalThreads', 'min', v)}
                onMaxChange={(v) => handleRangeChange('totalThreads', 'max', v)}
              />
            </div>
          </div>
        )}

        {/* Main preview */}
        {activeResult && (
          <div className="space-y-8 animate-fadeIn">
            <MainPreview threadcount={activeThreadcount} weave={weave} />

            <WeaveSelector
              threadcount={activeThreadcount}
              activeWeave={weave}
              onChange={setWeave}
            />

            {/* Threadcount */}
            <div>
              <div className="flex items-center justify-between mb-2">
                <h2 className="text-xs font-mono uppercase tracking-widest text-[var(--text-tertiary)]">
                  Thread Count
                </h2>
                <button
                  onClick={() => navigator.clipboard.writeText(activeThreadcount)}
                  className="text-xs text-[var(--accent)] hover:underline font-medium"
                >
                  Copy
                </button>
              </div>
              <div className="bg-[var(--bg-card)] border border-[var(--border)] rounded-lg
                             px-4 py-3 text-sm font-mono text-[var(--text-secondary)]
                             break-all leading-relaxed select-all">
                {activeThreadcount}
              </div>
            </div>

            {/* Seed */}
            <div className="text-xs font-mono text-[var(--text-tertiary)]">
              Seed: {activeResult.seed}
            </div>
          </div>
        )}

        {/* Empty state */}
        {!activeResult && (
          <div className="rounded-xl border-2 border-dashed border-[var(--border)] py-20 text-center">
            <p className="text-[var(--text-tertiary)] text-sm">
              Press Generate to create a random tartan
            </p>
          </div>
        )}

        {/* History rail */}
        {history.length > 1 && (
          <div>
            <h2 className="text-xs font-mono uppercase tracking-widest text-[var(--text-tertiary)] mb-3">
              History
            </h2>
            <div className="flex gap-3 overflow-x-auto no-scrollbar pb-2">
              {history.map((result, i) => (
                <HistoryThumb
                  key={`${result.seed}-${i}`}
                  result={result}
                  isActive={i === activeIndex}
                  onClick={() => setActiveIndex(i)}
                />
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Range control component
// ---------------------------------------------------------------------------

function RangeControl({
  label,
  min,
  max,
  absMin,
  absMax,
  onMinChange,
  onMaxChange,
}: {
  label: string;
  min: number;
  max: number;
  absMin: number;
  absMax: number;
  onMinChange: (v: number) => void;
  onMaxChange: (v: number) => void;
}) {
  return (
    <div>
      <label className="text-xs text-[var(--text-secondary)] block mb-1.5">
        {label}: {min} - {max}
      </label>
      <div className="flex items-center gap-2">
        <input
          type="range"
          min={absMin}
          max={absMax}
          value={min}
          onChange={(e) => onMinChange(Math.min(Number(e.target.value), max))}
          className="flex-1 h-1 bg-[var(--border)] rounded-full appearance-none cursor-pointer
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3.5 [&::-webkit-slider-thumb]:h-3.5
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer"
        />
        <input
          type="range"
          min={absMin}
          max={absMax}
          value={max}
          onChange={(e) => onMaxChange(Math.max(Number(e.target.value), min))}
          className="flex-1 h-1 bg-[var(--border)] rounded-full appearance-none cursor-pointer
                     [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-3.5 [&::-webkit-slider-thumb]:h-3.5
                     [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-[var(--accent)]
                     [&::-webkit-slider-thumb]:cursor-pointer"
        />
      </div>
    </div>
  );
}
